<main className="p-4">
  {/* Header row */}
  <div className="flex items-center justify-between mb-6 relative">
    <h1 className="text-xl font-bold">Scenario Name</h1>
    <div className="absolute left-1/2 transform -translate-x-1/2">
      <h1 className="text-xl font-bold">Scenario Components</h1>
    </div>
  </div>

  {/* Scenario Input (left) + Template Dropdown (center) */}
  <div className="grid grid-cols-3 gap-6 mb-6 items-center">
    {/* Left column */}
    <ScenarioInput onChange={setScenarioName} />

    {/* Center column */}
    <div className="flex justify-center">
      <TemplateDropdown onSelect={setTemplateId} />
    </div>

    {/* Right column (empty, just balances layout) */}
    <div></div>
  </div>

  {/* Node Name input */}
  <div className="flex justify-center mb-6">
    <NameNode onChange={setNodeName} />
  </div>

  {/* Add Node button */}
  <div className="flex justify-center">
    <button
      onClick={addNode}
      className="px-4 py-2 bg-green-500 text-white rounded hover:bg-green-600"
    >
      Add Node
    </button>
  </div>

  {/* Node list */}
  <ul className="mt-4">
    {nodes.map((node, idx) => (
      <li key={idx}>
        {node.name} ({node.template_id}) x:{node.x} y:{node.y}
      </li>
    ))}
  </ul>

  {/* Save button */}
  <button
    onClick={saveScenario}
    className="mt-4 px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600"
  >
    Save Scenario
  </button>
</main>
